var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤엑, 힉, 히엑……! 주, 주주, 죽겠어요……!","JPN":"ふえっ、ひいっ、ひええっ……！　し、しし、死にます……！","ENG":"*Huff* *Huff* Pant* *Pant*... I-I can't...! I'm dying...!","TWN":"哈哈，呼，呼哈……！我，我，我快死了……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, 벌써 페이스가 흐트러지면 어떡해요.","JPN":"ノエルさん、もうペースが乱れたらどうするんですか？","ENG":"You can't fall behind already, Noelle.","TWN":"洛艾兒，要穩住呼吸。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아직 2킬로미터는 더 뛰어야 돼요. 꿈을 이루게 도와 준다면서요.","JPN":"まだ2キロは走らないと。夢を叶えられるように手伝ってくれるって言ったでしょう？","ENG":"You need to run two kilometers more, at the very least. Didn't you say you'd help me make my dreams come true?","TWN":"還得再跑二公里呢。你不是說要幫我實現夢想嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 잠깐 쉬고 다시 뛰자. 이러다 송장 치우겠다.","JPN":"おい、ちょっと休んでから走らないか。これじゃあ、後で死体を運ぶことになりかねない。","ENG":"Yo, we should probably take a break before we have to put her in a body bag.","TWN":"小鬼，讓她休息一下吧，再跑下去就要替她收屍了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으, 저에겐 너무 힘든 도전이었나 봐요….","JPN":"うう、私にはとても無理な挑戦だったようです……","ENG":"Ouugh... Maybe this was too big a challenge for me...","TWN":"嗚嗚，這個挑戰，對我來說好像太難了……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"유리한 고지를 선점하는 것도 결국 체력 싸움인데….","JPN":"有利な場所を先取りするのも結局は体力次第なのに……","ENG":"Taking and maintaining the high ground is eventually a matter of stamina...","TWN":"說到底搶佔具有優勢的高地也是體力之戰……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇게 기초 체력도 부족하면서 건틀렛에 나가려고 했어요?","JPN":"こんなに基礎体力もないのに、ガントレットに出ようとしたのですか？","ENG":"Why did you decide to compete in the first place, especially when you're in such bad shape?","TWN":"你的體能那麼差，還想參加聖鎧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"별 수 있냐. 원래부터 엔트리에 이름만 빌려 줄 예정이었잖아.","JPN":"仕方ないだろ。元々エントリーに名前だけ貸してもらう予定だったんだし。","ENG":"What can we do? Besides, she was just an extra name on our entry list.","TWN":"有什麼辦法？她本來就是用來湊人數的嘛。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래도 드론보다는 쓸모가 있어야죠. 카운터 한 명에 포인트가 얼만데.","JPN":"それでも、ドローンよりは役に立たないと。カウンター一人に、何ポイントかかってると思っているの？","ENG":"Shouldn't she be better than a drone, at least? It takes a fortune to register a Counter.","TWN":"那她也應該比無人機更有用吧，制裁者消耗的點數比較多欸。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘의 역할은 단독으로 움직이면서 유리한 고지를 선점한 뒤 적을 견제하는 거예요.","JPN":"ノエルさんの役割は単独で動いて有利な場所を先に占有した後、敵を牽制することです。","ENG":"Your job is to act alone, take the high ground, and mark the enemies.","TWN":"洛艾兒你負責單獨行動，搶佔有優勢的高地後牽制敵人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"마음 단단히 먹어요. 실전에서도 이렇게 낙오되면 그냥 버릴 테니까요.","JPN":"気を引き締めてください。実戦でもこんな風に脱落したら、そのまま捨てちゃいますから。","ENG":"Get yourself together. If you can't keep up with us in the actual competition, we're just going to leave you behind.","TWN":"你做好心理準備。如果在實戰中也這樣脫隊，我們是會棄你不顧的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"며, 명심하겠습니다!","JPN":"りょ、了解いたしました！","ENG":"Y-yes, ma'am!","TWN":"我，我記住了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"꽤 강도 높은 트레이닝을 하는군.","JPN":"結構ハードなトレーニングをするんだな。","ENG":"The training seems to be quite intense.","TWN":"訓練的強度很強呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저러다 키가 안 큰다고 하니까 자기는 그게 좋대요. 피탄 면적은 작을수록 좋다나.","JPN":"そうしてると背が伸びないよって言っても、自分はそれがいいんですって。被弾面積は狭いほどいいとか？","ENG":"I told her she's not going to get any taller like that, and she said she prefers it. Says she doesn't want to be a bigger target or something.","TWN":"我跟她說訓練過度會長不高，結果她說這樣才好，因為不容易被子彈打到。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"사실 펠리세트가 독해서 그렇지, 제대로 지원 못 받는 팀들은 대부분 저런 식이에요.","JPN":"正直フェリセットは根性があるから大丈夫なだけで、ちゃんとしたサポートを受けられないチームはほとんどがあんな感じなんです。","ENG":"Well, Félicette is pretty tough, but most teams who don't get proper funding are like that.","TWN":"那孩子也是有苦衷的，其實得不到援助的隊伍大部分都是這樣的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"훈련 시설 대여비는 시즌 중에 엄청 뛰고, 연습용 탄환도 한 발 한 발이 지출이니까요.","JPN":"シーズン中の訓練施設の賃貸料は跳ね上がるし、練習用の弾丸も一発一発が全部お金ですから。","ENG":"The rent for training centers skyrockets during the competition season, not to mention the price of ammo used for practice.","TWN":"訓練場地的租金在賽季期間會猛漲，每一發練習用彈藥也都是錢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아. 어서 와, 사장님. 아침부터 야단법석이지?","JPN":"あ。いらっしゃい、社長。朝から騒がしいだろ？","ENG":"Oh, welcome, Boss. It's quite a racket here, ain't it?","TWN":"老闆來啦。一早就很熱鬧吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여기까지 무슨 일이세요? 같이 훈련하려고요?","JPN":"ここにはどういったご用ですか？　一緒に訓練でもするつもりですか？","ENG":"What brings you all the way here? Do you want to join training?","TWN":"老闆怎麼會來？想一起訓練嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아니. 너희들이 어떻게 훈련하는지 궁금해서 보러 오신 거야.","JPN":"ううん。あなたたちがどうやって訓練しているのか、気になって見に来られたんだよ。","ENG":"No. He's here because he was curious about how you were training.","TWN":"不是，老闆就是好奇你們是怎麼訓練的，所以過來看看。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"어쩌면 약간의 어드바이스도 있지 않을까? 안 그래요, 사장님?","JPN":"ひょっとしたら、ちょっとしたアドバイスなんかもあるかも？　どうですか？　社長。","ENG":"Perhaps a little bit of advice, Boss?","TWN":"也許還有一些建議吧？對嗎，老闆？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어드바이스요?","JPN":"アドバイス？","ENG":"Advice?","TWN":"建議？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양은 같이 움직이면서 화력 지원만 하는 편이 어떤가?","JPN":"ノエル君は一緒に動きながら、火力の支援だけをするのはどうかな？","ENG":"Why don't you let Noelle move together and focus on fire support?","TWN":"讓洛艾兒和你們一起行動，提供火力支援怎麼樣？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"흐음…. 단독 행동은 위험하다는 거지?","JPN":"ふむ……単独行動は危険ってことだろ？","ENG":"Hmm... Acting alone would be dangerous, huh?","TWN":"嗯……意思是她單獨一個人行動很危險對吧……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"확실히 일리는 있네. 저 상태로는.","JPN":"確かに一理はあるな。あの状態では。","ENG":"You do have a point. Seeing how she is right now.","TWN":"以她那種狀態，確實有道理。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"엔트리를 채워 주신 건 감사하고 있어요.","JPN":"エントリーに協力してくれたことには感謝しています。","ENG":"I'm grateful for you filling up the entry list.","TWN":"我很感謝老闆幫忙解決人數的問題。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만 카나리아 스쿼드의 리더는 저예요. 전술에 대한 결정권은 저에게 있어요.","JPN":"ですが、カナリア・スクワッドのリーダーは私です。戦術の決定権は私にあります。","ENG":"But I am the leader of Canary Squad. I make the tactical decisions.","TWN":"不過金絲雀小隊的隊長是我，戰術的決定權也在我手裡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희에게 부족한 건 실전에서 호흡을 맞춘 경험뿐이에요.","JPN":"私たちに足りないのは、実戦で息を合わせた経験だけです。","ENG":"What we lack is teamwork experience on the field.","TWN":"我們所缺少的只是在實戰中配合的經驗。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그걸 단기간에 보완하긴 어렵죠. 시즌 개막까지 며칠 남지도 않았고요.","JPN":"それを短期間で補うのは簡単ではありません。シーズン開幕まで後数日しか残っていませんし。","ENG":"It's not easy to make up for it in a short amount of time. Especially when the season's merely days away.","TWN":"這一點很難在短時間內彌補，而且距離賽季開幕也沒剩幾天，"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 저는 가능한 선에서 최선을 다하려는 거예요.","JPN":"だからこそ、可能な範囲内で最善を尽くそうとしているんです。","ENG":"So I'm just trying to make the most out of what we have.","TWN":"所以我想全力以赴做到最好。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"맙소사! 그럼 전 이 지옥 같은 훈련에서 영영 벗어날 수 없는 건가요!?","JPN":"そんな！　じゃあ、私はこの地獄のような訓練から永遠に逃げられないのですか！？","ENG":"Goodness! Am I never getting out of this hellish training?!","TWN":"天哪！所以我永遠無法擺脫這種地獄式訓練嗎！？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"반응을 보니 아직 팔팔하네. 더 뛰어도 되겠다.","JPN":"反応を見るとまだピンピンしてるわね。もっと走っても大丈夫そうよ。","ENG":"Well, she still has enough energy to scream. Looks like she can train more.","TWN":"還能做出這麼大的反應，那你應該可以繼續訓練吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘에게 들었어요. 사장님네 회사엔 건틀렛 전문 팀이 없다고요.","JPN":"ノエルさんから聞きました。社長の会社には、ガントレット専門チームがないそうですね。","ENG":"I heard from Noelle that your company doesn't have a dedicated Gauntlet team.","TWN":"我聽洛艾兒說，老闆的公司沒有專門的聖鎧小隊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇다면 전문가인 제 말을 믿어 주세요.","JPN":"でしたら、専門家である私の言葉を信じてください。","ENG":"So please listen to me. I'm an expert.","TWN":"那就請你相信我這個專業人士的話。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그건 다음 경기 성적표를 보고 결정하지.","JPN":"それは次の試合の成績を見てから決めよう。","ENG":"I'll decide when I see the next round results.","TWN":"這就等看到下一場比賽的成績後再說吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"마음대로 하세요. 어른들은 원래 우유부단하니까요.","JPN":"ご自由にどうぞ。大人たちは元々優柔不断ですから。","ENG":"Go ahead. You adults are always indecisive.","TWN":"隨便你，大人就是優柔寡斷。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"기싸움은 그만해, 펠리세트.","JPN":"神経戦はやめて、フェリセット。","ENG":"Enough, Félicette.","TWN":"別耍脾氣，費莉塞特。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"사장님께서 오는 길에 마실 걸 사 주셨어. 마시고 해.","JPN":"社長がここに来る途中に飲み物を買ってくださったの。先にいただきましょう。","ENG":"Boss brought us drinks. Take one.","TWN":"來的路上，老闆買了喝的，喝完再繼續吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 정말요? 감사합니다!","JPN":"あっ、本当ですか？　ありがとうございます！","ENG":"Oh, really? Yay! Thanks!","TWN":"哇，真的嗎？謝謝老闆！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이야, 스폰서가 있으니까 삶의 질이 달라지네. 잘 마실게.","JPN":"いやー、スポンサーがいると生活の質が違うね。いただきます。","ENG":"Heh, life is so much better with a sponsor on your back, no? Thanks.","TWN":"哇，有了贊助商之後，生活品質都不一樣了呢，多謝老闆～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이, 너도 앉아서 숨 좀 돌려.","JPN":"おこちゃま、あんたも座って休憩しなよ。","ENG":"You too, kid. Get some rest.","TWN":"小鬼，你也坐下休息一會兒吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아뇨. 전 먼저 갈게요. 휴식 시간 끝났어요.","JPN":"いいえ。私は先に行くわ。休息はしたから。","ENG":"No, I'm gonna go. Break time's over.","TWN":"不，我先去訓練了，休息時間結束。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗…. 가 버렸어요.","JPN":"あっ……行っちゃいました。","ENG":"Ah... She left.","TWN":"呃……走掉咧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"놔 둬. 저렇게라도 해야 자기 마음이 편하다는데.","JPN":"ほっとけ。ああでもしないと心が落ち着かないんだってさ。","ENG":"Leave her be. If it makes her comfortable, let her have it her way.","TWN":"別管她，只有那樣她心裡才會舒服點。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"건틀렛 꿈나무치고는 스스로에게 너무 가혹하군.","JPN":"ガントレットの金の卵にしては、自分に厳しすぎるな。","ENG":"She's too harsh on herself, for a Gauntlet rookie.","TWN":"雖然是目標是聖鎧，但她對自己過份嚴苛呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"응? 사장님, 꼬맹이에게 관심 있어?","JPN":"あ？　社長、あいつに興味あるのか？","ENG":"Hm? Have you taken a liking to her, Boss?","TWN":"喔？老闆，你對這個小鬼有興趣嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"면담 예약 잡아 줄까? 크면 두고 보자고 벼르는 놈들이 한둘이어야지.","JPN":"面談の予約、取ってやろうか？　大人になったら覚悟しろってやつが多すぎてさ。","ENG":"I could book you a meeting with her. There are more than enough people in line, just waiting for her to grow up.","TWN":"要我替老闆安排機會嗎？有不少傢伙都在等她長大呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"당장 자기가 살던 보육원이랑도 원수지간이라는걸.","JPN":"以前暮らしてた保育園とも仲が悪いんだ。","ENG":"Even the orphanage she grew up in resents her.","TWN":"她現在跟自己生活過的育幼院也是冤家對頭。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그 전에 몇 가지 물어 봐도 되겠나?","JPN":"その前に、聞いてみてもいいかな？","ENG":"Before that, would you mind if I asked some questions?","TWN":"我可以先問你幾個問題嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"직원에게 너무 친절하네. 좀 더 고압적인 타입인 줄 알았는데.","JPN":"社員にはすごく親切なんだな。もっと高飛車なタイプだと思ったんだけど。","ENG":"You're way too nice to your employees. I thought you would be more dictative.","TWN":"老闆對員工很親切呢，我還以為你是採取高壓政策那種。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"물어 봐. 내가 아는 한에선 얘기해 줄게.","JPN":"何でも聞いて。知ってる範囲で話してやるよ。","ENG":"Ask away. I'll tell you what I can.","TWN":"你問吧，我知無不答。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"둘이 어떻게 만난 건가?","JPN":"二人はどうやって出会ったんだい？","ENG":"How did you meet?","TWN":"你們二個是怎麼認識的？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"결승에 진출하려는 이유가 뭐지?","JPN":"決勝に進出しようとする理由は何だい？","ENG":"Why do you want to make it to the finals?","TWN":"那孩子想打入決賽的原因是什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 들었다.","JPN":"話してくれてありがとう。","ENG":"All good. Thanks.","TWN":"沒事。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하수구에서 장기 투숙하다가. 사람 갖다 파는 놈들에게 끌려가고 있었지, 아마.","JPN":"下水道で長期間寝泊りしてた頃だったな。あいつが人を売り飛ばす奴らに引っ張られていくところだったんだよ、たぶん。","ENG":"I was living in the sewers for quite some time, and I saw some dudes dragging her away for human trafficking.","TWN":"我本來長期在下水道露宿，直到有一天撞見她被幾個像人口販子的傢伙拖著走。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사람을 갖다 판다고요? 관리국 직할 도시에서요?","JPN":"人を売り飛ばす？　管理局直轄の都市でですか？","ENG":"Human trafficking? In an Administration Direct Control City?","TWN":"販賣人口？在管理局直轄市裡？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여긴 원래 그래. 사람한테 가격표 붙인다고 벼락 안 떨어지잖아.","JPN":"ここは元々そんなところなんだ。人に値段をつけたからって、天罰が下るわけでもないだろ？","ENG":"Things have always been like that here. There won't be any divine intervention for putting a price tag on someone.","TWN":"這裡就是這樣，反正給人貼上價格也不會遭雷劈。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼 애가 목청이 워낙 커서 소음공해 수준이었거든.","JPN":"とにかく、あいつの声が騒音公害レベルにデカくてさ。","ENG":"Anyway, her scream was more than a racket, it was basically noise pollution.","TWN":"總之，她的嗓門超級大，簡直就是噪音污染等級的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래서 조용히 시키려고, 인신매매범 놈들 뒤로 가서 쓱삭 해 버렸지.","JPN":"それで静かにさせようと思って、後ろから近づいて人身売買犯のやつらをサクっとやっつけたんだ。","ENG":"So I snuck up behind those guys and slashed them to shut her up.","TWN":"為了讓她安靜下來，我就溜到後面，把那幫人口販子全都解決掉。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미안. 그건 역시 나라도 좀.","JPN":"悪い。いくら私でも、それはちょっと。","ENG":"Sorry. Feels kinda wrong to tell you.","TWN":"抱歉，這個問題我也不好回答。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"다른 사람 입으로 들을 만큼 좋은 이유는 아니거든.","JPN":"他人の口から聞くほどいい理由じゃないからな。","ENG":"It's not a story that should be told by someone else.","TWN":"因為我覺得這個故事不應該從別人的嘴裡說出來。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까 정 궁금하면 저 꼬맹이 주둥이를 열 방법을 찾아 봐.","JPN":"だから、本当に知りたいんなら、あのおこちゃまの口を開かせる方法を探してみてよ。","ENG":"If you're really curious, find a way to make that kid open up.","TWN":"所以如果你真想知道，就自己想辦法讓那個小鬼開口吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 이거면 음료수 값은 됐지?","JPN":"ああ、飲み物代にはなっただろ？","ENG":"Well? I hope that was enough for the drink.","TWN":"這樣喔？那就算是抵我的飲料錢囉？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럼 나 먼저 간다. 노엘 넌 천천히 따라와.","JPN":"じゃあ、お先。ノエル、あんたは後からゆっくり来な。","ENG":"I'm gonna go. You can take your time to catch up, Noelle.","TWN":"那我先回去訓練了。洛艾兒，你喝完再回來。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"먼저 사무실로 돌아가라는 선택지는 없던 건가요!? 충격!","JPN":"先に事務所に戻れと言う選択肢はなかったんですか！？　ショック！","ENG":"There's no option of going back to the office?! I'm SHOOK!","TWN":"沒有叫我先回辦公室的選項嗎！？震驚！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L48_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"스키너 양, 혹시 프로그래밍 쪽에 조예는 있나?","JPN":"スキナー君、もしかしてプログラミングの知識はあるかい？","ENG":"Skinner, do you happen to be familiar with programming?","TWN":"史金納，你在程式設計方面有所涉獵嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"전자전 공부할 때 조금 배웠어요. 그쪽 계통 사람들 눈엔 걸음마 수준이겠지만요.","JPN":"電子戦を勉強するときにちょっと教わりました。そっち方面の人たちからしたら素人レベルでしょうけど。","ENG":"I learned a bit when I was studying electronic warfare. It's nothing compared to the people who work in the field, though.","TWN":"我只有在學習電子戰時學過一點。在老闆這種專業人士眼裡，應該很初階……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그 정도면 충분해.","JPN":"その程度で十分だ。","ENG":"That will be enough.","TWN":"那就夠了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하드웨어는 내가 손볼 테니, 자네는 소프트웨어 쪽을 좀 거들어 주게.","JPN":"ハードウェアは私が修理するから、君はソフトウェアの方を少し手伝ってくれたまえ。","ENG":"I'll take a look at the hardware, and I'd like your assistance with the software.","TWN":"硬體我會處理，要請你在軟體方面幫個小忙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 네. 설계만 만들어 주시면 못 도와 드릴 건 없죠.","JPN":"あ、はい。設計さえしてくださればお手伝いできると思います。","ENG":"Okay. As long as you give me the overall design, I don't see why not.","TWN":"喔，好，老闆負責設計的話，我沒問題。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그런데…. 어디에 쓰시려고요?","JPN":"でも……どこに使うんですか？","ENG":"But... what is this for?","TWN":"不過……老闆打算用來做什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};